#pragma once
// ============================================================================
// scoring_1124.hpp — SQP/SQD 模型 (46→1124 特征, 来自 Namerena-HtmlTools)
//
// 特征差异 (vs XP/XD 44→1034):
//   - 技能频次: 衰减叠加 (zd/kill 系数), 而非原始频次
//   - 护盾(x[37]): 非线性变换 ≤70→x²/70, >70→2x-70
//   - 铁壁(x[26]): 护盾>0 时移入 x[45], 原位清零
//   - Shadow: 加权线性组合, 而非简单减法
//   - 隐匿(x[42]): 设 x[44]=1 标志位, 不+20
//   - 多项式展开: 46→1124 (含 4 对排除: (26,37)(26,45)(42,44)(44,44))
//
// 评分模型:
//   MODEL_QP0[1124] — SQP (强评) 线性模型
//   MODEL_QD0[1124] — SQD (强单) 线性模型
//
// 注: 加入 V 值过滤器 (高 V*3>=1200 / 低 V*3>=1140+条件), 过滤低分名字以提升性能。
// ============================================================================
// 技能 ID 映射表 (来自 pbb_all.cpp skillNameMap)
//   0:火球术    1:冰冻术    2:雷击术    3:地裂术    4:吸血攻击  5:投毒
//   6:连击      7:会心一击  8:瘟疫      9:生命之轮  10:狂暴术   11:魅惑
//   12:加速术   13:减速术   14:诅咒     15:治愈魔法  16:苏生术   17:净化
//   18:铁壁     19:蓄力     20:聚气     21:潜行      22:血祭     23:分身
//   24:幻术     25:防御     26:守护     27:伤害反弹  28:护身符   29:护盾
//   30:反击     31:吞噬     32:召唤亡灵 33:垂死抗争  34:隐匿
//   35-39:啧(占位,无实际技能)
// ============================================================================
#include "common.hpp"
#include "name.hpp"

// ===== ScoreResult: 评分结果结构体 =====
struct ScoreResult {
  int xp;           // SQP 分数
  int xd;           // SQD 分数
  int sum;          // V + 252 = 八围总分
  int props[8];     // 8 个属性值 (加 36 偏移后的值)
  int skills[16];   // 16 个槽的技能 ID
  int freqs[16];    // 16 个槽的技能频次
  int flag3;        // 未使用 (保留接口兼容)
  int shadow;       // 未使用
  bool flag;        // 始终 true (此路径不过滤)
};

