// ===== poly_1124: 多项式特征扩展 (预计算表版) =====
// 46 维 → 1123 维 (一阶 46 + 二阶 1077, 排除 4 对)
// 模型权重 1124 维 = bias(1) + 1123 特征
inline void poly_1124(double *xp, const double *x) {
  for (int y = 0; y < 1123; y++) {
    auto& e = POLY_TABLE_1124[y];
    xp[y] = e.is_pair ? x[e.p] * x[e.q] : x[e.p];
  }
}

// ===== score_full: 完整评分流水线 (SQP/SQD) =====
// 不做 V 值检查, 对所有名字直接评分。
// 返回值: ScoreResult, flag 始终为 true
inline ScoreResult score_full(const char* name, int name_len, Name& name_obj) {
  ScoreResult result = {};
  memset(&result, 0, sizeof(result));

  // ---- Step 1: 加载名字, 提取属性 ----
  name_obj.load_name(name, name_len);

  int prop[8];
  prop[0] = median(name_obj.name_base[10], name_obj.name_base[11], name_obj.name_base[12]);
  prop[1] = median(name_obj.name_base[13], name_obj.name_base[14], name_obj.name_base[15]);
  prop[2] = median(name_obj.name_base[16], name_obj.name_base[17], name_obj.name_base[18]);
  prop[3] = median(name_obj.name_base[19], name_obj.name_base[20], name_obj.name_base[21]);
  prop[4] = median(name_obj.name_base[22], name_obj.name_base[23], name_obj.name_base[24]);
  prop[5] = median(name_obj.name_base[25], name_obj.name_base[26], name_obj.name_base[27]);
  prop[6] = median(name_obj.name_base[28], name_obj.name_base[29], name_obj.name_base[30]);
  prop[7] = 154 + name_obj.name_base[3] + name_obj.name_base[4]
                + name_obj.name_base[5] + name_obj.name_base[6];

  int V = name_obj.V;

  // ---- Step 2: V 值双路径检查 (性能优化, 与 XP/XD 相同) ----
  bool check_skills = false;
  bool is_high_path = (V * 3 >= 1200);
  bool is_low_path  = (V * 3 >= 1140 && prop[6] >= 36
                       && prop[1] + prop[2] + prop[5] + prop[6] >= 175);
  if (is_high_path || is_low_path)
    check_skills = true;
  if (!check_skills) {
    result.flag = false;
    return result;
  }

  // ---- Step 3: 技能分布 ----
  name_obj.calc_skills(name);

  // ---- Step 4: 构建 46 维特征向量 xp_x ----
  double xp_x[46] = {};

  // 属性标准化
  for (int j = 0; j < 7; j++) {
    prop[j] += 36;
    result.props[j] = prop[j];
    xp_x[j + 1] = prop[j];
  }
  xp_x[0] = prop[7];  // HP
  result.props[7] = prop[7];

  // 技能频次: 衰减叠加 (zd/kill 系数)
  for (int i = 0; i < 35; i++) xp_x[i + 8] = 0;

  double zd = 1.0, kill = 1.0;
  for (int k = 0; k < 16; k++) {
    int sk = name_obj.skill[k];
    double f = name_obj.freq[k];
    if (f == 0) continue;

    if (sk == 9 || sk == 16) {        // 生命之轮(9)/苏生术(16)
      xp_x[sk + 8] = zd * f;
      zd *= (1.0 - f * 0.30 / 128.0);
    } else if (sk == 18) {            // 铁壁(18)
      xp_x[sk + 8] = zd * f;
      zd *= (1.0 - f * 0.35 / 128.0);
    } else if (sk == 19 || sk == 23) { // 蓄力(19)/分身(23)
      xp_x[sk + 8] = zd * f;
      zd *= (1.0 - f * 0.60 / 128.0);
    } else if (sk == 20 || sk == 22) { // 聚气(20)/血祭(22)
      xp_x[sk + 8] = zd * f;
      zd *= (1.0 - f * 0.70 / 128.0);
    } else if (sk < 25) {             // 一般主动技能
      xp_x[sk + 8] = zd * f;
      zd *= (1.0 - f * 1.00 / 128.0);
    } else if (sk == 31 || sk == 32) { // 吞噬(31)/召唤亡灵(32)
      xp_x[sk + 8] = kill * f;
      kill *= (1.0 - f * 1.00 / 128.0);
    } else {
      xp_x[sk + 8] = f;               // 被动技能: 不衰减
    }
  }

  // 护盾(xp_x[37], skill ID 29) 非线性变换
  if (xp_x[37] <= 70.0)
    xp_x[37] = xp_x[37] * xp_x[37] / 70.0;
  else
    xp_x[37] = xp_x[37] * 2.0 - 70.0;

  // ---- Step 5: 暗影二段评分 ----
  if (xp_x[32] > 0) {
    char shadow_name[260];
    memcpy(shadow_name, name, name_len);
    shadow_name[name_len] = '?';
    shadow_name[name_len+1] = 's'; shadow_name[name_len+2] = 'h';
    shadow_name[name_len+3] = 'a'; shadow_name[name_len+4] = 'd';
    shadow_name[name_len+5] = 'o'; shadow_name[name_len+6] = 'w';
    shadow_name[name_len+7] = 0;

    name_obj.loading_name(shadow_name);
    int sprop[8];
    sprop[0] = median(name_obj.name_base[10], name_obj.name_base[11], name_obj.name_base[12]);
    sprop[1] = median(name_obj.name_base[13], name_obj.name_base[14], name_obj.name_base[15]);
    sprop[2] = median(name_obj.name_base[16], name_obj.name_base[17], name_obj.name_base[18]);
    sprop[3] = median(name_obj.name_base[19], name_obj.name_base[20], name_obj.name_base[21]);
    sprop[4] = median(name_obj.name_base[22], name_obj.name_base[23], name_obj.name_base[24]);
    sprop[5] = median(name_obj.name_base[25], name_obj.name_base[26], name_obj.name_base[27]);
    sprop[6] = median(name_obj.name_base[28], name_obj.name_base[29], name_obj.name_base[30]);
    sprop[7] = 154 + name_obj.name_base[3] + name_obj.name_base[4]
                   + name_obj.name_base[5] + name_obj.name_base[6];

    double shadowi = sprop[0]*2.8 + sprop[1]*0.6 + sprop[2]*2.5
                   + sprop[3]*1.2 + sprop[4]*1.0 + sprop[5]*1.0
                   - sprop[6]*1.2 + sprop[7]*0.8;
    xp_x[43] = shadowi * xp_x[32] / 100.0;
  }

  // 隐匿(xp_x[42], skill ID 34): 标志位, 不 +20
  if (xp_x[42] > 0) xp_x[44] = 1.0;

  // 护盾 > 0: 守护(x[26]) → x[45], 原位清零
  if (xp_x[37] > 0) {
    xp_x[45] = xp_x[26];
    xp_x[26] = 0;
  }

  // ---- Step 6: 多项式扩展 + 模型评分 ----
  double xp_array[1123];
  poly_1124(xp_array, xp_x);

  // SQP 评分
  float score_qp = MODEL_QP0[0];  // bias
  for (int i = 0; i < 1123; i++)
    score_qp += xp_array[i] * MODEL_QP0[i + 1];

  // SQD 评分
  float score_qd = MODEL_QD0[0];  // bias
  for (int i = 0; i < 1123; i++)
    score_qd += xp_array[i] * MODEL_QD0[i + 1];

  result.xp = (int)score_qp;
  result.xd = (int)score_qd;
  result.sum = V + 36 * 7;
  result.flag = true;

  return result;
}
